class Solution:
    def distinctIntegers(self, n):
        board = {n}
        frontier = {n}
        while frontier:
            new_frontier = set()
            for x in frontier:
                for i in range(1, n + 1):
                    if x % i == 1 and i not in board:
                        new_frontier.add(i)
            board |= new_frontier
            frontier = new_frontier
        return len(board)

